using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private readonly List<RecipeCategory> _categories;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple yet delicious pizza with fresh tomatoes, mozzarella, and basil.",
                ImageUrl = "🍕",
                Ingredients = ["2 cups flour", "1 cup warm water", "1 tbsp yeast", "Fresh mozzarella", "San Marzano tomatoes", "Fresh basil", "Olive oil", "Salt"],
                Steps = ["Mix flour, water, yeast, and salt to form dough.", "Let dough rise for 1 hour.", "Stretch dough into a circle on a floured surface.", "Spread crushed tomatoes over the dough.", "Add torn mozzarella pieces.", "Bake at 475°F for 12-15 minutes.", "Top with fresh basil and a drizzle of olive oil."],
                TotalRatings = 24, RatingSum = 108
            },
            new Recipe
            {
                Id = 2, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken pieces in a creamy, spiced tomato sauce.",
                ImageUrl = "🍛",
                Ingredients = ["1 lb chicken breast", "1 cup yogurt", "2 tbsp tikka masala paste", "1 can crushed tomatoes", "1 cup heavy cream", "1 onion, diced", "3 cloves garlic", "Fresh cilantro"],
                Steps = ["Marinate chicken in yogurt and spices for 2 hours.", "Grill or broil chicken until charred.", "Sauté onion and garlic until soft.", "Add tomato paste and crushed tomatoes; simmer 10 minutes.", "Stir in cream and tikka masala paste.", "Add chicken pieces and simmer 15 minutes.", "Garnish with cilantro and serve with rice."],
                TotalRatings = 31, RatingSum = 147
            },
            new Recipe
            {
                Id = 3, Title = "Beef Tacos", Category = "Mexican",
                Description = "Seasoned ground beef tacos with fresh toppings.",
                ImageUrl = "🌮",
                Ingredients = ["1 lb ground beef", "Taco seasoning", "Corn tortillas", "Shredded lettuce", "Diced tomatoes", "Shredded cheese", "Sour cream", "Hot sauce"],
                Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water; simmer until thickened.", "Warm tortillas in a dry skillet.", "Fill tortillas with seasoned beef.", "Top with lettuce, tomatoes, cheese, and sour cream.", "Add hot sauce to taste."],
                TotalRatings = 18, RatingSum = 78
            },
            new Recipe
            {
                Id = 4, Title = "Pad Thai", Category = "Asian",
                Description = "Stir-fried rice noodles with shrimp, peanuts, and tangy sauce.",
                ImageUrl = "🍜",
                Ingredients = ["8 oz rice noodles", "1/2 lb shrimp", "2 eggs", "Bean sprouts", "3 tbsp fish sauce", "2 tbsp tamarind paste", "1 tbsp sugar", "Crushed peanuts", "Lime wedges"],
                Steps = ["Soak rice noodles in warm water for 30 minutes; drain.", "Mix fish sauce, tamarind paste, and sugar for the sauce.", "Stir-fry shrimp until pink; set aside.", "Scramble eggs in the same wok.", "Add noodles and sauce; toss until coated.", "Add shrimp and bean sprouts; toss together.", "Serve with crushed peanuts and lime wedges."],
                TotalRatings = 22, RatingSum = 95
            },
            new Recipe
            {
                Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts",
                Description = "Rich chocolate cake with a molten center.",
                ImageUrl = "🍫",
                Ingredients = ["4 oz dark chocolate", "1/2 cup butter", "1 cup powdered sugar", "2 eggs", "2 egg yolks", "6 tbsp flour", "Butter and cocoa for ramekins"],
                Steps = ["Preheat oven to 425°F.", "Melt chocolate and butter together.", "Stir in powdered sugar, eggs, and egg yolks.", "Fold in flour until just combined.", "Grease ramekins with butter and dust with cocoa.", "Pour batter into ramekins.", "Bake for 12-14 minutes until edges are set but center is soft.", "Invert onto plates and serve immediately."],
                TotalRatings = 35, RatingSum = 168
            },
            new Recipe
            {
                Id = 6, Title = "Caesar Salad", Category = "Salads",
                Description = "Crisp romaine lettuce with classic Caesar dressing and croutons.",
                ImageUrl = "🥗",
                Ingredients = ["1 head romaine lettuce", "1/2 cup Caesar dressing", "1/4 cup parmesan cheese", "Croutons", "2 anchovy fillets", "1 clove garlic", "1 lemon, juiced", "Olive oil"],
                Steps = ["Wash and chop romaine lettuce.", "Make dressing: blend anchovies, garlic, lemon juice, and olive oil.", "Toss lettuce with dressing.", "Top with shaved parmesan and croutons.", "Season with black pepper and serve."],
                TotalRatings = 14, RatingSum = 56
            },
            new Recipe
            {
                Id = 7, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Creamy pasta with pancetta, egg, and parmesan.",
                ImageUrl = "🍝",
                Ingredients = ["1 lb spaghetti", "6 oz pancetta", "4 egg yolks", "1 cup parmesan cheese", "Black pepper", "Salt"],
                Steps = ["Cook spaghetti in salted water until al dente.", "Crisp pancetta in a skillet.", "Whisk egg yolks with parmesan and pepper.", "Drain pasta, reserving 1 cup pasta water.", "Toss hot pasta with pancetta.", "Remove from heat; stir in egg mixture quickly.", "Add pasta water as needed for a creamy sauce."],
                TotalRatings = 28, RatingSum = 131
            },
            new Recipe
            {
                Id = 8, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh avocado dip with lime and cilantro.",
                ImageUrl = "🥑",
                Ingredients = ["3 ripe avocados", "1 lime, juiced", "1 tsp salt", "1/2 cup cilantro", "1/2 onion, diced", "2 roma tomatoes, diced", "1 jalapeño, minced", "1 clove garlic, minced"],
                Steps = ["Halve avocados and remove pits.", "Mash avocado in a bowl to desired consistency.", "Stir in lime juice and salt.", "Mix in onion, cilantro, tomatoes, jalapeño, and garlic.", "Taste and adjust seasoning.", "Serve immediately with tortilla chips."],
                TotalRatings = 20, RatingSum = 90
            }
        ];

        _categories =
        [
            new RecipeCategory { Name = "Italian", Icon = "🇮🇹", Description = "Pasta, pizza, and Mediterranean flavors", RecipeCount = 2 },
            new RecipeCategory { Name = "Indian", Icon = "🇮🇳", Description = "Rich curries and aromatic spices", RecipeCount = 1 },
            new RecipeCategory { Name = "Mexican", Icon = "🇲🇽", Description = "Bold flavors with fresh ingredients", RecipeCount = 2 },
            new RecipeCategory { Name = "Asian", Icon = "🥢", Description = "Stir-fries, noodles, and umami", RecipeCount = 1 },
            new RecipeCategory { Name = "Desserts", Icon = "🍰", Description = "Sweet treats and baked goods", RecipeCount = 1 },
            new RecipeCategory { Name = "Salads", Icon = "🥗", Description = "Fresh, healthy, and colorful", RecipeCount = 1 }
        ];

        _nextId = _recipes.Max(r => r.Id) + 1;
    }

    public List<RecipeCategory> GetCategories() => _categories;

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public void SubmitRecipe(RecipeSubmission submission)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = submission.Title,
            Category = submission.Category,
            Description = submission.Description,
            Ingredients = submission.Ingredients
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = submission.Steps
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            ImageUrl = "📝"
        };

        _recipes.Add(recipe);

        var category = _categories.FirstOrDefault(c =>
            c.Name.Equals(submission.Category, StringComparison.OrdinalIgnoreCase));
        if (category is not null)
        {
            category.RecipeCount++;
        }
    }
}

