@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= (_hovered > 0 ? _hovered : _selected) ? "filled" : "")"
              @onclick="() => Rate(star)"
              @onmouseover="() => _hovered = star"
              @onmouseout="() => _hovered = 0"
              role="button"
              title="Rate @star star@(star > 1 ? "s" : "")">
            ★
        </span>
    }
    @if (_submitted)
    {
        <span class="rating-thanks">Thanks!</span>
    }
    else if (AverageRating > 0)
    {
        <span class="rating-info">@AverageRating.ToString("0.0") (@TotalRatings ratings)</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
