                                        <span>⭐ @recipe.AverageRating.ToString("0.0") (@recipe.TotalRatings ratings)</span>
                                    }
                                    else
                                    {
                                        <span>No ratings yet</span>
                                    }
                                </small>
                                <span class="badge bg-primary">View Recipe →</span>
                            </div>
                        </div>
                    </div>
                </a>
            </div>
        }
    </div>
}

@code {
