@page "/recipe/{Id:int}"
@using RecipeHub.Services
@using RecipeHub.Components.Shared

@inject RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe") — RecipeHub</PageTitle>

@if (Recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="category/@Recipe.Category">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        </ol>
    </nav>

    <div class="recipe-detail">
        <div class="d-flex align-items-center mb-3">
            <span class="recipe-emoji-lg me-3">@Recipe.ImageUrl</span>
            <div>
                <h1 class="mb-1">@Recipe.Title</h1>
                <span class="badge bg-info">@Recipe.Category</span>
            </div>
        </div>

        <p class="lead">@Recipe.Description</p>

        <div class="mb-4">
            <h5>Rate this recipe:</h5>
            <StarRating RecipeId="@Recipe.Id"
                        AverageRating="@Recipe.AverageRating"
                        TotalRatings="@Recipe.TotalRatings"
                        OnRated="HandleRating" />
        </div>

        <div class="row">
            <div class="col-md-4 mb-4">
                <div class="card">
                    <div class="card-header bg-success text-white">
                        <h5 class="mb-0">🧂 Ingredients</h5>
                    </div>
                    <ul class="list-group list-group-flush">
                        @foreach (var ingredient in Recipe.Ingredients)
                        {
                            <li class="list-group-item">@ingredient</li>
                        }
                    </ul>
                </div>
            </div>

            <div class="col-md-8 mb-4">
                <div class="card">
                    <div class="card-header bg-primary text-white">
                        <h5 class="mb-0">📋 Steps</h5>
                    </div>
                    <div class="card-body">
                        <ol class="recipe-steps">
                            @foreach (var step in Recipe.Steps)
                            {
                                <li class="mb-2">@step</li>
                            }
                        </ol>
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private RecipeHub.Models.Recipe? Recipe { get; set; }

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetRecipeById(Id);
    }

    private void HandleRating(int stars)
    {
        RecipeService.AddRating(Id, stars);
        Recipe = RecipeService.GetRecipeById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Models
@using RecipeHub.Services

@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe — RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

<h1 class="mb-4">📝 Submit a Recipe</h1>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>🎉 Recipe submitted!</h4>
        <p>Your recipe "<strong>@_model.Title</strong>" has been added. <a href="category/@_model.Category">View it in @_model.Category</a>.</p>
    </div>
}
else
{
    <div class="card shadow-sm">
        <div class="card-body">
            <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
                <DataAnnotationsValidator />

                <div class="mb-3">
                    <label for="title" class="form-label">Recipe Title</label>
                    <InputText id="title" @bind-Value="_model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
                    <ValidationMessage For="() => _model.Title" />
                </div>

                <div class="mb-3">
                    <label for="category" class="form-label">Category</label>
                    <InputSelect id="category" @bind-Value="_model.Category" class="form-select">
                        <option value="">— Select a category —</option>
                        @foreach (var cat in RecipeService.GetCategories())
                        {
                            <option value="@cat.Name">@cat.Icon @cat.Name</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => _model.Category" />
                </div>

                <div class="mb-3">
                    <label for="description" class="form-label">Description</label>
                    <InputTextArea id="description" @bind-Value="_model.Description" class="form-control" rows="2" placeholder="A brief description of your recipe" />
                </div>

                <div class="mb-3">
                    <label for="ingredients" class="form-label">Ingredients</label>
                    <InputTextArea id="ingredients" @bind-Value="_model.Ingredients" class="form-control" rows="5" placeholder="One ingredient per line&#10;e.g.,&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" />
                    <small class="form-text text-muted">Enter one ingredient per line.</small>
                </div>

                <div class="mb-3">
                    <label for="steps" class="form-label">Steps</label>
                    <InputTextArea id="steps" @bind-Value="_model.Steps" class="form-control" rows="5" placeholder="One step per line&#10;e.g.,&#10;Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients" />
                    <small class="form-text text-muted">Enter one step per line.</small>
                </div>

                <button type="submit" class="btn btn-success btn-lg" disabled="@(!IsValid)">Submit Recipe</button>
            </EditForm>
        </div>
    </div>
}

@code {
    private RecipeSubmission _model = new();
    private bool _submitted;

    private bool IsValid => !string.IsNullOrWhiteSpace(_model.Title)
                         && !string.IsNullOrWhiteSpace(_model.Category)
                         && !string.IsNullOrWhiteSpace(_model.Ingredients)
                         && !string.IsNullOrWhiteSpace(_model.Steps);

    private void HandleSubmit()
    {
        if (!IsValid) return;
        RecipeService.SubmitRecipe(_model);
        _submitted = true;
    }
}

